'use client'
import { useState, useEffect } from 'react'
import { 
  CurrencyDollarIcon,
  ShoppingBagIcon,
  UserGroupIcon,
  ExclamationTriangleIcon,
  ChartBarIcon,
  ArrowTrendingUpIcon,
  ArrowTrendingDownIcon
} from '@heroicons/react/24/outline'
import { useSalesStore } from '@/store/useSalesStore'
import { useProductStore } from '@/store/useProductStore'
import { useAuthStore } from '@/store/useAuthStore'

export default function DashboardPage() {
  const { getSalesForLast30Days, getGrossIncome, getNetIncome } = useSalesStore()
  const { products } = useProductStore()
  const { getCurrentTenant, isAdmin, isStaff } = useAuthStore()
  const [activePeriod, setActivePeriod] = useState('Today')
  const [dashboardData, setDashboardData] = useState({
    totalRevenue: 0,
    totalOrders: 0,
    customerCount: 0,
    lowStockCount: 0,
    profitMargin: 0,
    isLoading: true
  })
  
  const currentTenant = getCurrentTenant()
  const userIsAdmin = isAdmin()
  const userIsStaff = isStaff()

  const periods = ['Today', 'Week', 'Month', 'Year']

  // Calculate dashboard data in real-time
  useEffect(() => {
    const calculateDashboardData = () => {
      const now = new Date()
      let startDate = new Date()
      
      switch (activePeriod) {
        case 'Today':
          startDate.setHours(0, 0, 0, 0)
          break
        case 'Week':
          startDate.setDate(now.getDate() - 7)
          break
        case 'Month':
          startDate.setDate(now.getDate() - 30)
          break
        case 'Year':
          startDate.setFullYear(now.getFullYear() - 1)
          break
      }

      const sales = getSalesForLast30Days(currentTenant || undefined).filter(sale => {
        const saleDate = new Date(sale.date)
        return saleDate >= startDate && saleDate <= now
      })

      const totalRevenue = sales.reduce((sum, sale) => sum + sale.total, 0)
      const totalOrders = sales.length
      const customerCount = new Set(sales.map(sale => sale.paymentMethod + sale.date.toISOString())).size // Unique transactions
      
      // Calculate low stock items (filtered by tenant)
      const tenantProducts = currentTenant ? products.filter(p => p.tenantId === currentTenant) : products
      const lowStockCount = tenantProducts.filter(product => 
        product.lowStockAlert && product.stock <= product.lowStockAlert && product.stock > 0
      ).length

      // Calculate profit margin (only for admin users)
      let profitMargin = 0
      if (userIsAdmin) {
        const gross = getGrossIncome(startDate, now, currentTenant || undefined)
        const net = getNetIncome(startDate, now, currentTenant || undefined)
        profitMargin = gross > 0 ? (net / gross) * 100 : 0
      }

      setDashboardData({
        totalRevenue,
        totalOrders,
        customerCount,
        lowStockCount,
        profitMargin,
        isLoading: false
      })
    }

    calculateDashboardData()
    
    // Set up interval for real-time updates (every 5 seconds)
    const interval = setInterval(calculateDashboardData, 5000)
    
    return () => clearInterval(interval)
  }, [activePeriod, getSalesForLast30Days, getGrossIncome, getNetIncome, products, currentTenant, userIsAdmin])

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-PH', { 
      style: 'currency', 
      currency: 'PHP' 
    }).format(amount)
  }

  const stats = [
    {
      title: 'Total Revenue',
      amount: formatCurrency(dashboardData.totalRevenue),
      change: dashboardData.totalRevenue > 0 ? '+' : '',
      icon: CurrencyDollarIcon,
      iconColor: 'bg-emerald-100 text-emerald-600',
      trend: 'up'
    },
    {
      title: 'Total Orders',
      amount: dashboardData.totalOrders.toString(),
      change: dashboardData.totalOrders > 0 ? '+' : '',
      icon: ShoppingBagIcon,
      iconColor: 'bg-blue-100 text-blue-600',
      trend: 'up'
    },
    {
      title: 'Customer Count',
      amount: dashboardData.customerCount.toString(),
      change: dashboardData.customerCount > 0 ? '+' : '',
      icon: UserGroupIcon,
      iconColor: 'bg-purple-100 text-purple-600',
      trend: 'up'
    },
    {
      title: 'Low Stock Alerts',
      amount: dashboardData.lowStockCount.toString(),
      change: dashboardData.lowStockCount > 0 ? '⚠️' : '✓',
      icon: ExclamationTriangleIcon,
      iconColor: dashboardData.lowStockCount > 0 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600',
      trend: dashboardData.lowStockCount > 0 ? 'down' : 'up'
    }
  ]

  // Get recent sales data (filtered by tenant)
  const recentSales = getSalesForLast30Days(currentTenant || undefined).slice(-5).reverse()

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <div className="flex gap-2">
          {periods.map((period) => (
            <button
              key={period}
              onClick={() => setActivePeriod(period)}
              className={`px-4 py-2 rounded-lg font-medium transition-all ${
                activePeriod === period
                  ? 'bg-emerald-600 text-white shadow-lg'
                  : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50'
              }`}
            >
              {period}
            </button>
          ))}
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
        {stats.map((stat, index) => {
          const Icon = stat.icon
          const TrendIcon = stat.trend === 'up' ? ArrowTrendingUpIcon : ArrowTrendingDownIcon
          
          return (
            <div key={index} className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm hover:shadow-md transition-shadow">
              <div className="flex items-center justify-between mb-4">
                <div className={`p-3 rounded-lg ${stat.iconColor}`}>
                  <Icon className="size-6" />
                </div>
                <div className="flex items-center gap-1">
                  <TrendIcon className={`size-4 ${stat.trend === 'up' ? 'text-green-500' : 'text-red-500'}`} />
                  <span className={`text-sm font-medium ${stat.trend === 'up' ? 'text-green-600' : 'text-red-600'}`}>
                    {stat.change}
                  </span>
                </div>
              </div>
              <div className="space-y-1">
                <p className="text-sm text-gray-600">{stat.title}</p>
                <p className="text-2xl font-bold text-gray-900">{stat.amount}</p>
              </div>
            </div>
          )
        })}
      </div>

      {/* Profit Margin Card - Admin Only */}
      {userIsAdmin ? (
        <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-emerald-100 rounded-lg">
                <ChartBarIcon className="size-6 text-emerald-600" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-gray-900">Profit Margin</h3>
                <p className="text-sm text-gray-600">Net profit as percentage of revenue</p>
              </div>
            </div>
            <div className="text-3xl font-bold text-emerald-600">
              {dashboardData.profitMargin.toFixed(1)}%
            </div>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-3">
            <div 
              className="bg-linear-to-r from-emerald-400 to-emerald-600 h-3 rounded-full transition-all duration-500"
              style={{ width: `${Math.min(dashboardData.profitMargin, 100)}%` }}
            />
          </div>
        </div>
      ) : (
        <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
          <div className="flex items-center justify-center mb-4">
            <div className="flex items-center gap-3">
              <div className="p-3 bg-gray-100 rounded-lg">
                <ChartBarIcon className="size-6 text-gray-400" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-gray-900">Profit Margin</h3>
                <p className="text-sm text-gray-500">Access restricted to Admin users</p>
              </div>
            </div>
            <div className="text-3xl font-bold text-gray-400 ml-4">
              ***
            </div>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-3">
            <div className="bg-gray-300 h-3 rounded-full" style={{ width: '0%' }} />
          </div>
        </div>
      )}

      {/* Recent Sales Table */}
      <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">Recent Sales</h2>
          <div className="text-sm text-gray-500">
            {dashboardData.isLoading ? 'Updating...' : 'Live Data'}
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-gray-200">
                <th className="text-left py-3 px-4 text-gray-600 font-medium">Time</th>
                <th className="text-left py-3 px-4 text-gray-600 font-medium">Items</th>
                <th className="text-left py-3 px-4 text-gray-600 font-medium">Payment</th>
                <th className="text-right py-3 px-4 text-gray-600 font-medium">Amount</th>
                {userIsAdmin && <th className="text-right py-3 px-4 text-gray-600 font-medium">Profit</th>}
              </tr>
            </thead>
            <tbody>
              {recentSales.map((sale) => {
                const costOfGoods = sale.items.reduce((cost, item) => {
                  return cost + (item.costPrice ? item.costPrice * item.qty : 0)
                }, 0)
                const profit = sale.total - costOfGoods
                
                return (
                  <tr key={sale.id} className="border-b border-gray-100 hover:bg-gray-50">
                    <td className="py-3 px-4 text-sm text-gray-900">
                      {new Date(sale.date).toLocaleTimeString('en-PH', { 
                        hour: '2-digit', 
                        minute: '2-digit' 
                      })}
                    </td>
                    <td className="py-3 px-4 text-sm text-gray-900">
                      {sale.items.length} item{sale.items.length !== 1 ? 's' : ''}
                    </td>
                    <td className="py-3 px-4 text-sm text-gray-900 capitalize">{sale.paymentMethod}</td>
                    <td className="py-3 px-4 text-sm font-medium text-emerald-600 text-right">
                      {formatCurrency(sale.total)}
                    </td>
                    {userIsAdmin && (
                      <td className="py-3 px-4 text-sm font-medium text-right">
                        <span className={profit >= 0 ? 'text-green-600' : 'text-red-600'}>
                          {formatCurrency(profit)}
                        </span>
                      </td>
                    )}
                  </tr>
                )
              })}
              {recentSales.length === 0 && (
                <tr>
                  <td className="py-8 px-4 text-center text-gray-500" colSpan={userIsAdmin ? 5 : 4}>
                    No recent sales data available
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Quick Stats Footer */}
      <div className="grid gap-4 md:grid-cols-3">
        <div className="bg-emerald-50 border border-emerald-200 rounded-lg p-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-emerald-100 rounded-lg">
              <CurrencyDollarIcon className="size-5 text-emerald-600" />
            </div>
            <div>
              <div className="text-sm text-emerald-600 font-medium">Today's Revenue</div>
              <div className="text-lg font-bold text-emerald-900">
                {formatCurrency(dashboardData.totalRevenue)}
              </div>
            </div>
          </div>
        </div>
        
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-blue-100 rounded-lg">
              <ShoppingBagIcon className="size-5 text-blue-600" />
            </div>
            <div>
              <div className="text-sm text-blue-600 font-medium">Active Orders</div>
              <div className="text-lg font-bold text-blue-900">
                {dashboardData.totalOrders}
              </div>
            </div>
          </div>
        </div>
        
        <div className={`${dashboardData.lowStockCount > 0 ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'} border rounded-lg p-4`}>
          <div className="flex items-center gap-3">
            <div className={`p-2 ${dashboardData.lowStockCount > 0 ? 'bg-red-100' : 'bg-green-100'} rounded-lg`}>
              <ExclamationTriangleIcon className={`size-5 ${dashboardData.lowStockCount > 0 ? 'text-red-600' : 'text-green-600'}`} />
            </div>
            <div>
              <div className={`text-sm ${dashboardData.lowStockCount > 0 ? 'text-red-600' : 'text-green-600'} font-medium`}>
                Stock Status
              </div>
              <div className={`text-lg font-bold ${dashboardData.lowStockCount > 0 ? 'text-red-900' : 'text-green-900'}`}>
                {dashboardData.lowStockCount > 0 ? `${dashboardData.lowStockCount} Alerts` : 'All Good'}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}